// Basic Style Functions (p5.js context needed)
function applyTextStyle(p, { color = COLORS.text, size = FONT_SIZE_UI, align = p.LEFT } = {}) {
    p.fill(color);
    p.textSize(size);
    p.textAlign(align, p.CENTER);
    p.noStroke();
}

// --- lib/utils.js ---

// Fisher-Yates (Knuth) Shuffle algorithm
function shuffleArray(array) {
    let currentIndex = array.length, randomIndex;
    while (currentIndex !== 0) {
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex--;
        [array[currentIndex], array[randomIndex]] = [
            array[randomIndex], array[currentIndex]];
    }
    return array;
}

// Function to scramble letters of a word
function scrambleWord(word) {
    if (!word) return '';
    let letters = word.split('');
    // Keep shuffling until it's different from the original (unless it's 1 letter)
    let maxAttempts = 10;
    let attempts = 0;
    let shuffledWord = word;
    if (letters.length > 1) {
        do {
            letters = shuffleArray(letters);
            shuffledWord = letters.join('');
            attempts++;
        } while (shuffledWord === word && attempts < maxAttempts);
        // If it's still the same after attempts (e.g., "OO"), just return the shuffled one
    }
    return shuffledWord;
}

// Check if point is inside a rectangle
function isPointInRect(px, py, rx, ry, rw, rh) {
    return px >= rx && px <= rx + rw && py >= ry && py <= ry + rh;
}

// Get flag emoji from language code
function getFlagEmoji(langCode) {
    const flags = {
        it: '🇮🇹',
        en: '🏴󠁧󠁢󠁥󠁮󠁧󠁿', // Or '🇬🇧'
        de: '🇩🇪',
        fr: '🇫🇷',
    };
    return flags[langCode] || '🏳️';
}

