// --- lib/drawing.js --- (Functions that draw stuff)

function drawStartScreen(p) {
    p.background(BACKGROUND_COLOR);
    applyTextStyle(p, { size: 32, align: p.CENTER });
    p.text('Word Scramble Fun! 🤪', p.width / 2, 50);

    // Language Selection
    applyTextStyle(p, { size: FONT_SIZE_UI, align: p.LEFT });
    p.text('Choose Languages:', 50, 120);
    uiElements.langToggles = []; // Reset for drawing
    let toggleX = 50;
    const toggleY = 150;
    const toggleW = 80;
    const toggleH = 30;
    availableLanguages.forEach((lang, index) => {
        const flag = getFlagEmoji(lang);
        const isSelected = selectedLanguages.includes(lang);
        const x = toggleX + index * (toggleW + 15);

        // Store button info
        uiElements.langToggles.push({ x, y: toggleY, w: toggleW, h: toggleH, lang });

        // Draw button
        p.stroke(COLORS.letterBorder);
        p.fill(isSelected ? COLORS.toggleOn : COLORS.toggleOff);
        p.rect(x, toggleY, toggleW, toggleH, 5); // Rounded corners

        // Draw text/emoji
        applyTextStyle(p, { size: FONT_SIZE_UI, color: isSelected ? COLORS.text : '#888', align: p.CENTER });
        p.text(`${flag} ${lang.toUpperCase()}`, x + toggleW / 2, toggleY + toggleH / 2 + 5); // Adjust vertical align
    });


    // Difficulty Selection
    applyTextStyle(p, { size: FONT_SIZE_UI, align: p.LEFT });
    p.text('Choose Difficulty:', 50, 230);
    uiElements.difficultyButtons = [];
    let diffButtonX = 50;
    const diffButtonY = 260;
    const diffButtonW = 100;
    const diffButtonH = 40;
    ['easy', 'medium', 'hard'].forEach((diff, index) => {
        const isSelected = selectedDifficulty === diff;
        const x = diffButtonX + index * (diffButtonW + 15);

        uiElements.difficultyButtons.push({ x, y: diffButtonY, w: diffButtonW, h: diffButtonH, difficulty: diff });

        p.stroke(COLORS.letterBorder);
        p.fill(isSelected ? COLORS.buttonHover : COLORS.buttonBg);
        p.rect(x, diffButtonY, diffButtonW, diffButtonH, 5);

        applyTextStyle(p, { size: FONT_SIZE_UI, color: COLORS.buttonText, align: p.CENTER });
        p.text(diff.charAt(0).toUpperCase() + diff.slice(1), x + diffButtonW / 2, diffButtonY + diffButtonH / 2 + 5);
    });

    // Start Button
    const startBtnW = 150;
    const startBtnH = 50;
    const startBtnX = p.width / 2 - startBtnW / 2;
    const startBtnY = p.height - 100;
    uiElements.startButton = { x: startBtnX, y: startBtnY, w: startBtnW, h: startBtnH };

    p.fill(COLORS.buttonBg);
    if (isPointInRect(p.mouseX, p.mouseY, startBtnX, startBtnY, startBtnW, startBtnH)) {
        p.fill(COLORS.buttonHover); // Hover effect
    }
    p.rect(startBtnX, startBtnY, startBtnW, startBtnH, 10);
    applyTextStyle(p, { size: 24, color: COLORS.buttonText, align: p.CENTER });
    p.text('Start Game!', startBtnX + startBtnW / 2, startBtnY + startBtnH / 2 + 8);
}

function drawPlayingScreen(p) {
    p.background(BACKGROUND_COLOR);

     // Flash background if just got correct
    if (correctFlashTime > 0 && p.millis() < correctFlashTime + 500) {
        p.background(COLORS.correctHighlight);
        if (p.millis() > correctFlashTime + 490) correctFlashTime = 0; // Stop flashing
    } else {
         p.background(BACKGROUND_COLOR);
    }


    // Draw Score and Word Count
    applyTextStyle(p, { size: FONT_SIZE_UI, align: p.LEFT });
    p.text(`Score: ${score} ❤️`, 20, 30);
    p.text(`Word: ${wordsPlayed + 1} / ${MAX_WORDS_PER_GAME}`, p.width - 150, 30);

    // Draw Timer
    let elapsedTime = (p.millis() - startTime) / 1000;
    applyTextStyle(p, { size: FONT_SIZE_UI, align: p.CENTER });
    p.text(`Time: ${elapsedTime.toFixed(1)}s`, p.width / 2, 30);


    // Draw Emoji
    if (currentWordData) {
        applyTextStyle(p, { size: FONT_SIZE_EMOJI, align: p.CENTER });
        p.text(currentWordData.emoji, p.width / 2, 90);
    }

    // Draw Word Rows
    let startX = p.width / 2; // Center alignment starting point
    wordStates.forEach((langState, langIndex) => {
        const yPos = START_Y_OFFSET + langIndex * ROW_SPACING;
        const totalWidth = langState.currentLetters.length * (LETTER_SIZE + LETTER_SPACING) - LETTER_SPACING;
        let currentX = startX - totalWidth / 2;

        // Draw Flag
        applyTextStyle(p, { size: FLAG_SIZE });
        p.text(getFlagEmoji(langState.lang), currentX - FLAG_SIZE - 15, yPos + LETTER_SIZE / 2 + 5); // Adjust alignment slightly

        // Draw Letters
        langState.letterBoxes = []; // Reset boxes for hit detection
        langState.currentLetters.forEach((letter, letterIndex) => {
            // Store position and size for interaction
            langState.letterBoxes.push({ x: currentX, y: yPos, w: LETTER_SIZE, h: LETTER_SIZE });

            // Determine background color
            let bgColor = COLORS.letterBg;
            if (keyboardState.selectedRow === langIndex && keyboardState.selectedCol === letterIndex) {
                 bgColor = COLORS.letterBgSelectedKeyboard; // Keyboard selection highlight
            }
            // Check if this letter is one of the two selected for keyboard swap
             const isKeyboardSelected = keyboardState.selectedLetters.some(sel => sel.langIndex === langIndex && sel.letterIndex === letterIndex);
             if(isKeyboardSelected) {
                 bgColor = COLORS.letterBgSelected; // Highlight for keyboard swap pair
             }


            // Draw the letter box
            p.stroke(COLORS.letterBorder);
            p.fill(bgColor);
            p.rect(currentX, yPos, LETTER_SIZE, LETTER_SIZE, 5); // Rounded corners

            // Draw the letter
            applyTextStyle(p, { size: FONT_SIZE_LETTER, align: p.CENTER });
            p.text(letter.toUpperCase(), currentX + LETTER_SIZE / 2, yPos + LETTER_SIZE / 2 + (FONT_SIZE_LETTER / 3)); // Vertical center adjust

            currentX += LETTER_SIZE + LETTER_SPACING;
        });
    });

     // Draw dragging letter last so it's on top
     if (dragging.active) {
        const { langIndex, letterIndex, offsetX, offsetY } = dragging;
        const letter = wordStates[langIndex].currentLetters[letterIndex];
        const dragX = p.mouseX - offsetX;
        const dragY = p.mouseY - offsetY;

        p.stroke(COLORS.letterBorder);
        p.fill(COLORS.letterBgSelected); // Highlight dragging letter
        p.rect(dragX, dragY, LETTER_SIZE, LETTER_SIZE, 5);
        applyTextStyle(p, { size: FONT_SIZE_LETTER, align: p.CENTER });
        p.text(letter.toUpperCase(), dragX + LETTER_SIZE / 2, dragY + LETTER_SIZE / 2 + (FONT_SIZE_LETTER / 3));
     }
}

function drawGameOverScreen(p) {
    p.background(BACKGROUND_COLOR);
    applyTextStyle(p, { size: 48, align: p.CENTER, color: '#dc143c' }); // Crimson Red
    p.text('Game Over! 🎉', p.width / 2, p.height / 2 - 60);

    applyTextStyle(p, { size: 32, align: p.CENTER });
    p.text(`Final Score: ${score} ❤️`, p.width / 2, p.height / 2);

    // Play Again Button
    const btnW = 200;
    const btnH = 60;
    const btnX = p.width / 2 - btnW / 2;
    const btnY = p.height / 2 + 60;
    uiElements.playAgainButton = { x: btnX, y: btnY, w: btnW, h: btnH };

    p.fill(COLORS.buttonBg);
    if (isPointInRect(p.mouseX, p.mouseY, btnX, btnY, btnW, btnH)) {
        p.fill(COLORS.buttonHover); // Hover effect
    }
    p.rect(btnX, btnY, btnW, btnH, 10);
    applyTextStyle(p, { size: 24, color: COLORS.buttonText, align: p.CENTER });
    p.text('Play Again?', btnX + btnW / 2, btnY + btnH / 2 + 8);
}


// --- lib/game_logic.js --- (Functions that manage the game flow)

function startGame(p) {
    // Filter words based on difficulty
    const difficultiesToInclude = [];
    if (selectedDifficulty === 'easy') {
        difficultiesToInclude.push('easy');
    } else if (selectedDifficulty === 'medium') {
        difficultiesToInclude.push('easy', 'medium');
    } else { // hard
        difficultiesToInclude.push('easy', 'medium', 'hard');
    }

    const availableWords = words.filter(word => difficultiesToInclude.includes(word.difficulty));

     if (availableWords.length === 0) {
        console.error("No words found for the selected difficulty!");
        // Maybe show an error message instead of just console logging
        gameState = 'START_SCREEN'; // Go back to start
        return;
     }


    score = 0;
    wordsPlayed = -1; // Will be incremented to 0 by nextWord
    gameState = 'PLAYING';
    nextWord(p, availableWords);
}

function nextWord(p, wordPool) {
    wordsPlayed++;
    if (wordsPlayed >= MAX_WORDS_PER_GAME) {
        gameState = 'GAME_OVER';
        return;
    }

    currentWordData = p.random(wordPool); // Get a random word object from the filtered pool
    wordStates = []; // Reset states for the new word

    selectedLanguages.forEach(lang => {
        const correctWord = currentWordData[lang];
        if (correctWord) { // Make sure the word exists for this language
            const scrambled = scrambleWord(correctWord);
            wordStates.push({
                lang: lang,
                correctWord: correctWord,
                scrambledWord: scrambled,
                currentLetters: scrambled.split(''),
                letterBoxes: [], // Will be populated during draw
                isCorrect: false,
            });
        } else {
            console.warn(`Word data missing for language '${lang}' in emoji ${currentWordData.emoji}`);
        }
    });

    // Reset keyboard selection for new word
    keyboardState.selectedRow = 0;
    keyboardState.selectedCol = 0;
    keyboardState.selectedLetters = [];


    startTime = p.millis(); // Start timer for this word
    correctFlashTime = 0; // Reset flash effect
    console.log(`Starting word ${wordsPlayed + 1}: ${currentWordData.emoji}`); // Debugging
}

function checkWinCondition(p, availableWords) {
    let allCorrect = true;
    wordStates.forEach(state => {
        const currentWord = state.currentLetters.join('');
        state.isCorrect = (currentWord === state.correctWord);
        if (!state.isCorrect) {
            allCorrect = false;
        }
    });

    if (allCorrect) {
        console.log("Word Correct!"); // Debugging
        correctFlashTime = p.millis(); // Trigger flash

        // Calculate score
        let elapsedTime = (p.millis() - startTime) / 1000;
        let points = 0;
        if (elapsedTime <= SCORE_THRESHOLDS.fast) {
            points = SCORE_POINTS.fast;
        } else if (elapsedTime <= SCORE_THRESHOLDS.medium) {
            points = SCORE_POINTS.medium;
        } else if (elapsedTime <= SCORE_THRESHOLDS.slow) {
            points = SCORE_POINTS.slow;
        } else {
            points = SCORE_POINTS.slowest;
        }
        score += points;

        // Give a slight delay before showing the next word
        setTimeout(() => {
            nextWord(p, availableWords); // Pass the filtered pool again
             // Reset keyboard selection on win
             keyboardState.selectedRow = 0;
             keyboardState.selectedCol = 0;
             keyboardState.selectedLetters = [];
        }, 600); // 600ms delay to see the flash/correct state
    }
}

function swapLetters(langIndex, index1, index2) {
    if (langIndex < 0 || langIndex >= wordStates.length) return; // Safety check
    const state = wordStates[langIndex];
    if (index1 < 0 || index1 >= state.currentLetters.length || index2 < 0 || index2 >= state.currentLetters.length) return; // Safety check

    // Swap the letters in the array
    [state.currentLetters[index1], state.currentLetters[index2]] =
        [state.currentLetters[index2], state.currentLetters[index1]];

    // No need to explicitly redraw here, the main draw() loop handles it.
}

// --- lib/input_handler.js --- (Functions handling mouse/keyboard)

function handleMousePressed(p) {
    if (gameState === 'START_SCREEN') {
        // Check Language Toggles
        uiElements.langToggles.forEach(toggle => {
            if (isPointInRect(p.mouseX, p.mouseY, toggle.x, toggle.y, toggle.w, toggle.h)) {
                const langIndex = selectedLanguages.indexOf(toggle.lang);
                if (langIndex > -1) {
                     // Prevent removing the last language
                    if (selectedLanguages.length > 1) {
                       selectedLanguages.splice(langIndex, 1);
                    }
                } else {
                    selectedLanguages.push(toggle.lang);
                }
            }
        });

        // Check Difficulty Buttons
        uiElements.difficultyButtons.forEach(button => {
            if (isPointInRect(p.mouseX, p.mouseY, button.x, button.y, button.w, button.h)) {
                selectedDifficulty = button.difficulty;
            }
        });

        // Check Start Button
        const startBtn = uiElements.startButton;
        if (startBtn && isPointInRect(p.mouseX, p.mouseY, startBtn.x, startBtn.y, startBtn.w, startBtn.h)) {
            if (selectedLanguages.length > 0) {
               startGame(p);
            } else {
                console.log("Please select at least one language!"); // Maybe show this on screen
            }
        }

    } else if (gameState === 'PLAYING') {
        // Check if clicking on a letter to start dragging
        for (let i = 0; i < wordStates.length; i++) {
            for (let j = 0; j < wordStates[i].letterBoxes.length; j++) {
                const box = wordStates[i].letterBoxes[j];
                if (isPointInRect(p.mouseX, p.mouseY, box.x, box.y, box.w, box.h)) {
                    dragging.active = true;
                    dragging.langIndex = i;
                    dragging.letterIndex = j;
                    dragging.offsetX = p.mouseX - box.x;
                    dragging.offsetY = p.mouseY - box.y;
                    // Clear keyboard selection when dragging starts
                    keyboardState.selectedLetters = [];
                    return; // Found the letter, stop checking
                }
            }
        }
    } else if (gameState === 'GAME_OVER') {
        // Check Play Again Button
        const playAgainBtn = uiElements.playAgainButton;
        if (playAgainBtn && isPointInRect(p.mouseX, p.mouseY, playAgainBtn.x, playAgainBtn.y, playAgainBtn.w, playAgainBtn.h)) {
            gameState = 'START_SCREEN'; // Reset to start screen
        }
    }
}

function handleMouseReleased(p, availableWords) {
    if (gameState === 'PLAYING' && dragging.active) {
        let droppedOnTarget = false;
        // Find which letter box (if any) the mouse was released over
        for (let i = 0; i < wordStates.length; i++) {
            // Can only drop on the same language row
            if (i === dragging.langIndex) {
                for (let j = 0; j < wordStates[i].letterBoxes.length; j++) {
                    // Don't swap with itself
                    if (j === dragging.letterIndex) continue;

                    const box = wordStates[i].letterBoxes[j];
                    if (isPointInRect(p.mouseX, p.mouseY, box.x, box.y, box.w, box.h)) {
                        // Swap the dragged letter with the target letter
                        swapLetters(dragging.langIndex, dragging.letterIndex, j);
                        droppedOnTarget = true;
                         checkWinCondition(p, availableWords); // Check if correct after swap
                        break; // Found drop target
                    }
                }
            }
            if (droppedOnTarget) break;
        }

        // Reset dragging state whether dropped on target or not
        dragging.active = false;
        dragging.letterIndex = -1;
        dragging.langIndex = -1;
    }
}

function handleKeyPressed(p, availableWords) {
     if (gameState !== 'PLAYING') return; // Keyboard only works during gameplay

     let rowChanged = false;
     let colChanged = false;

     if (p.keyCode === p.UP_ARROW) {
         if (keyboardState.selectedRow > 0) {
             keyboardState.selectedRow--;
             rowChanged = true;
         }
     } else if (p.keyCode === p.DOWN_ARROW) {
         if (keyboardState.selectedRow < wordStates.length - 1) {
             keyboardState.selectedRow++;
             rowChanged = true;
         }
     } else if (p.keyCode === p.LEFT_ARROW) {
         if (keyboardState.selectedCol > 0) {
             keyboardState.selectedCol--;
             colChanged = true;
         } else {
             // Wrap around to the end
             keyboardState.selectedCol = wordStates[keyboardState.selectedRow].currentLetters.length - 1;
              colChanged = true;
         }
     } else if (p.keyCode === p.RIGHT_ARROW) {
         if (keyboardState.selectedCol < wordStates[keyboardState.selectedRow].currentLetters.length - 1) {
             keyboardState.selectedCol++;
             colChanged = true;
         } else {
             // Wrap around to the beginning
             keyboardState.selectedCol = 0;
             colChanged = true;
         }
     } else if (p.key === ' ') { // Use p.key for spacebar
         p.preventDefault(); // Prevent page scroll
         const currentSelection = {
             langIndex: keyboardState.selectedRow,
             letterIndex: keyboardState.selectedCol
         };

         // Check if already selected, if so, deselect
         const existingIndex = keyboardState.selectedLetters.findIndex(
             sel => sel.langIndex === currentSelection.langIndex && sel.letterIndex === currentSelection.letterIndex
         );

         if (existingIndex !== -1) {
             keyboardState.selectedLetters.splice(existingIndex, 1);
         } else {
             // Add the new selection
             keyboardState.selectedLetters.push(currentSelection);
             // If more than 2 are selected, remove the oldest one
             if (keyboardState.selectedLetters.length > 2) {
                 keyboardState.selectedLetters.shift(); // Remove the first (oldest)
             }
         }
          console.log("Selected letters:", keyboardState.selectedLetters); // Debug

     } else if (p.keyCode === p.ENTER) {
        p.preventDefault();
        // Swap if exactly two letters are selected IN THE SAME ROW
         if (keyboardState.selectedLetters.length === 2) {
             const sel1 = keyboardState.selectedLetters[0];
             const sel2 = keyboardState.selectedLetters[1];

             // Ensure they are in the same language row
             if (sel1.langIndex === sel2.langIndex) {
                 console.log(`Swapping [${sel1.langIndex}, ${sel1.letterIndex}] with [${sel2.langIndex}, ${sel2.letterIndex}]`); // Debug
                 swapLetters(sel1.langIndex, sel1.letterIndex, sel2.letterIndex);
                 keyboardState.selectedLetters = []; // Clear selection after swap
                 checkWinCondition(p, availableWords); // Check if word is correct
             } else {
                 console.log("Cannot swap: letters are in different rows."); // Feedback
                 // Maybe add visual feedback here? For now, just clear selection.
                 keyboardState.selectedLetters = [];
             }
         } else {
             console.log("Cannot swap: need exactly two letters selected in the same row.");
              // Maybe add visual feedback here? For now, just clear selection.
             keyboardState.selectedLetters = [];
         }
     }

     // If row changed, adjust column if new row is shorter
     if (rowChanged) {
        const currentRowLength = wordStates[keyboardState.selectedRow].currentLetters.length;
        if (keyboardState.selectedCol >= currentRowLength) {
            keyboardState.selectedCol = currentRowLength - 1;
        }
        // Clear selections when changing row to avoid cross-row swaps
        keyboardState.selectedLetters = [];
     }
      // If column or row changed, ensure selection highlights update
     if (rowChanged || colChanged) {
         // The draw loop will handle the visual update based on selectedRow/Col
     }

}


