let p5Instance; // To hold the p5 instance

// We need to wrap the sketch in instance mode to properly pass `p` around
const sketch = (p) => {

    let fontRegular; // Variable to hold the loaded font (optional)

    // You might want to preload a font that supports all characters/emojis well
    // p.preload = () => {
    //    fontRegular = p.loadFont('assets/YourChosenFont.ttf'); // Make sure to upload font if using web editor
    // }

    p.setup = () => {
        p.createCanvas(window.innerWidth * 0.9, window.innerHeight * 0.9); // Responsive canvas
        // if (fontRegular) {
        //    p.textFont(fontRegular);
        // }
        // Inside p.setup function, after createCanvas
        p.canvas.style.touchAction = 'none';
        p.textFont('Arial'); // Default font
        p.textAlign(p.CENTER, p.CENTER);
        p.frameRate(30); // Keep it reasonable
        console.log("Game Setup Complete! Let's Play! 🎮");
         // Initialize UI element positions (needed if canvas size changes)
        // This is simple now, but could be more robust if needed
    };

     // Re-calculate UI element positions if window is resized
    p.windowResized = () => {
        p.resizeCanvas(window.innerWidth * 0.9, window.innerHeight * 0.9);
        // Re-init UI elements or recalculate positions if layout is dynamic
         console.log("Window resized, canvas updated.");
    };


    p.draw = () => {
        // Determine which pool of words to use based on difficulty (needed for checkWinCondition)
        const difficultiesToInclude = [];
        if (selectedDifficulty === 'easy') difficultiesToInclude.push('easy');
        else if (selectedDifficulty === 'medium') difficultiesToInclude.push('easy', 'medium');
        else difficultiesToInclude.push('easy', 'medium', 'hard');
        const currentWordPool = words.filter(word => difficultiesToInclude.includes(word.difficulty));


        switch (gameState) {
            case 'START_SCREEN':
                drawStartScreen(p);
                break;
            case 'PLAYING':
                drawPlayingScreen(p);
                break;
            case 'GAME_OVER':
                drawGameOverScreen(p);
                break;
        }
    };

    // Pass p5 instance to handlers
    p.mousePressed = () => handleMousePressed(p);
    p.mouseReleased = () => {
         // Determine the correct word pool *at the time of the event*
         const difficultiesToInclude = [];
         if (selectedDifficulty === 'easy') difficultiesToInclude.push('easy');
         else if (selectedDifficulty === 'medium') difficultiesToInclude.push('easy', 'medium');
         else difficultiesToInclude.push('easy', 'medium', 'hard');
         const currentWordPool = words.filter(word => difficultiesToInclude.includes(word.difficulty));
         handleMouseReleased(p, currentWordPool);
    }
    p.keyPressed = () => {
         // Determine the correct word pool *at the time of the event*
         const difficultiesToInclude = [];
         if (selectedDifficulty === 'easy') difficultiesToInclude.push('easy');
         else if (selectedDifficulty === 'medium') difficultiesToInclude.push('easy', 'medium');
         else difficultiesToInclude.push('easy', 'medium', 'hard');
         const currentWordPool = words.filter(word => difficultiesToInclude.includes(word.difficulty));
         handleKeyPressed(p, currentWordPool);
    }

};

// Initialize the sketch using p5 instance mode
p5Instance = new p5(sketch);
